class Solution:
    def sortTheStudents(self, score, k):
        rows = [row[:] for row in score]
        n = len(rows)
        for i in range(n):
            best = i
            for j in range(i + 1, n):
                if rows[j][k] > rows[best][k]:
                    best = j
            rows[i], rows[best] = rows[best], rows[i]
        return rows

